import{_ as o,o as c,c as a,ap as d}from"./chunks/framework.BaP7s1d0.js";const u=JSON.parse('{"title":"Package APIs","description":"","frontmatter":{},"headers":[],"relativePath":"api/packages.md","filePath":"api/packages.md"}'),r={name:"api/packages.md"};function i(t,e,s,l,n,p){return c(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="package-apis" tabindex="-1">Package APIs <a class="header-anchor" href="#package-apis" aria-label="Permalink to “Package APIs”">​</a></h1><p>This page summarizes the current public package surface in this monorepo.</p><h2 id="ptahjs-ui-vue" tabindex="-1"><code>@ptahjs/ui-vue</code> <a class="header-anchor" href="#ptahjs-ui-vue" aria-label="Permalink to “@ptahjs/ui-vue”">​</a></h2><p>Main integration package for Vue.</p><ul><li><code>createPtah(options)</code></li><li><code>useRuntimeApp(args)</code></li><li><code>useDesignerApp(args)</code></li><li>Built-in components: <code>DesignerRoot</code>, <code>Preview</code>, <code>WorkspaceWidget</code>, <code>ScenesWidget</code>, <code>ModulesWidget</code>, <code>EventsWidget</code>, <code>ParameterWidget</code>, <code>RendererModule</code>, <code>FpsWidget</code></li><li>Built-in renderers: <code>WebRenderer</code>, <code>SceneRenderer</code>, <code>FlowRenderer</code></li><li>Re-exports all APIs from <code>@ptahjs/runtime</code> and <code>@ptahjs/designer</code></li></ul><hr><h2 id="ptahjs-runtime" tabindex="-1"><code>@ptahjs/runtime</code> <a class="header-anchor" href="#ptahjs-runtime" aria-label="Permalink to “@ptahjs/runtime”">​</a></h2><p>Runtime layer based on Kernel.</p><ul><li>Classes: <code>Runtime</code>, <code>FlowRunner</code>, <code>ProgramLoader</code></li><li>Functions: <code>compilePageSchemaToSections</code>, <code>compilePageSchema</code>, <code>buildStackToTarget</code></li><li>Re-exports all APIs from <code>@ptahjs/kernel</code></li></ul><hr><h2 id="ptahjs-designer" tabindex="-1"><code>@ptahjs/designer</code> <a class="header-anchor" href="#ptahjs-designer" aria-label="Permalink to “@ptahjs/designer”">​</a></h2><p>Design-time layer.</p><ul><li>Class: <code>Designer</code></li><li>Schema factories: <code>createRootAppSchema</code>, <code>createSceneSchema</code>, <code>createModuleSchema</code>, <code>createPropsSchema</code>, <code>createEventsSchema</code>, <code>createSlotsSchema</code></li><li>Property helpers: <code>numberProp</code>, <code>stringProp</code>, <code>booleanProp</code>, <code>selectProp</code>, <code>objectProp</code>, <code>arrayProp</code>, <code>groupProp</code></li><li>Re-exports all APIs from <code>@ptahjs/dnd</code></li></ul><hr><h2 id="ptahjs-kernel" tabindex="-1"><code>@ptahjs/kernel</code> <a class="header-anchor" href="#ptahjs-kernel" aria-label="Permalink to “@ptahjs/kernel”">​</a></h2><p>Core state layer.</p><ul><li>Classes: <code>Kernel</code>, <code>ResourceRepository</code>, <code>ModuleManager</code>, <code>LifecycleChain</code>, <code>SharedResource</code></li><li>IR helpers: <code>createEmptyIRGraph</code>, <code>clearIRGraph</code>, <code>IR_SECTIONS</code>, <code>RUNTIME_STATE_KEYS</code>, selectors (<code>getSceneById</code>, <code>getModuleById</code>, ...)</li><li>Constants: <code>MODULE_TYPE</code>, <code>EVENT_TYPE</code>, <code>RESOURCE_TYPE</code>, <code>LIFECYCLE_TYPE</code>, <code>ROOT_SECTION</code></li><li>Compiler helper: <code>applyCompiledSectionsToKernel</code></li></ul><hr><h2 id="ptahjs-dnd" tabindex="-1"><code>@ptahjs/dnd</code> <a class="header-anchor" href="#ptahjs-dnd" aria-label="Permalink to “@ptahjs/dnd”">​</a></h2><p>Drag-and-drop engine.</p><ul><li>Core: <code>Dnd</code></li><li>Services: <code>DropService</code>, <code>MirrorService</code>, <code>AutoScrollService</code>, <code>DropIndicatorService</code>, <code>ActiveSelectionService</code>, <code>TransformControllerService</code></li></ul><hr><h2 id="ptahjs-shared" tabindex="-1"><code>@ptahjs/shared</code> <a class="header-anchor" href="#ptahjs-shared" aria-label="Permalink to “@ptahjs/shared”">​</a></h2><p>Shared utilities package.</p><p>Contains utility functions (<code>cloneDeep</code>, <code>debounce</code>, <code>orderBy</code>, ...), event infrastructure (<code>EventDispatcher</code>), hotkeys, storage helpers, websocket helpers, and more.</p><hr><h2 id="ptahjs-tri-core-ptahjs-tri-extensions" tabindex="-1"><code>@ptahjs/tri-core</code> / <code>@ptahjs/tri-extensions</code> <a class="header-anchor" href="#ptahjs-tri-core-ptahjs-tri-extensions" aria-label="Permalink to “@ptahjs/tri-core / @ptahjs/tri-extensions”">​</a></h2><p>3D engine and extension plugin packages.</p><ul><li><code>@ptahjs/tri-core</code>: <code>defineTri(args)</code> + engine/plugins/features exports</li><li><code>@ptahjs/tri-extensions</code>: core plugins + feature plugins + default export plugin list</li></ul><hr><h2 id="build-tooling-packages" tabindex="-1">Build Tooling Packages <a class="header-anchor" href="#build-tooling-packages" aria-label="Permalink to “Build Tooling Packages”">​</a></h2><ul><li><code>@ptahjs/build</code>: <code>buildConfig(options)</code></li><li><code>@ptahjs/vite-plugin-json</code>: Vite JSON plugin entry (<code>src/main.js</code>)</li></ul>',32)])])}const g=o(r,[["render",i]]);export{u as __pageData,g as default};
